CodeInjections.CodeInjection:
float3 getTangent(FS_INPUT In, FS_GLOBALS globals)
{
    return normalize(In.vs.worldTangent);
}
float3 getBitangent(FS_INPUT In, FS_GLOBALS globals)
{
    float3 tangentSpaceNormal = In.vs.worldNormal.xyz;
    float3 tangentSpaceTangent = In.vs.worldTangent.xyz;
    float3 tangentSpaceBitangent = cross(tangentSpaceNormal, tangentSpaceTangent)*In.vs.worldTangent.w;    
    return normalize(tangentSpaceBitangent);
}
float getWardAnisotropicNormalDistribution(float roughness, float anis, float NdotL, float NdotV, float NdotH, float HdotX, float HdotY)
{
    float aspect = sqrt(1.0h-anis * 0.9h);
    float X = max(.001, (roughness*roughness)/aspect) * 5;
    float Y = max(.001, (roughness*roughness)*aspect) * 5;
    float exponent = -((HdotX/X)*(HdotX/X) + (HdotY/Y)*(HdotY/Y)) / (NdotH*NdotH);
    float Distribution = 1.0 / (4.0 * 3.14159265 * X * Y * sqrt(NdotL * NdotV));
    Distribution *= exp(exponent);
    return Distribution;
}
float getTrowbridgeReitzAnisotropicNormalDistribution(float roughness,float anis, float NdotH, float HdotX, float HdotY)
{
    float aspect = sqrt(1.0h-anis * 0.9h);
    float X = max(.001, (roughness*roughness)/aspect) * 5;
    float Y = max(.001, (roughness*roughness)*aspect) * 5;
    float tmp = ((HdotX/X)*(HdotX/X) + (HdotY/Y)*(HdotY/Y) + NdotH*NdotH);
    return 1.0 / (  3.1415926535 * X*Y * tmp * tmp  );
}
// Anisotropic GGX
// [Burley 2012, "Physically-Based Shading at Disney"]
float getGGXaniso( float roughness,float RoughnessX, float RoughnessY, float NdotH, float HdotX, float HdotY )
{
    float ax = RoughnessX * RoughnessX;
    float ay = RoughnessY * RoughnessY;
    float d = HdotX * HdotX / (ax * ax) + HdotY * HdotY / (ay * ay) + NdotH * NdotH;
    return 1 / ( 3.1415926535 * ax * ay * d * d );
}

